#!/usr/bin/env python3

import os
import sys
import subprocess
import json
import hashlib
import argparse
from pathlib import Path
from typing import List, Dict, Optional, Set
import re
from datetime import datetime


class DependencyLockManager:
    """
    Manages Python dependency lock files for consistent environments.
    Supports both pip-tools (requirements.txt with hashes) and Poetry.
    """
    
    def __init__(self, project_root: str = "."):
        self.project_root = Path(project_root).resolve()
        self.requirements_in = self.project_root / "requirements.in"
        self.requirements_txt = self.project_root / "requirements.txt"
        self.requirements_dev_in = self.project_root / "requirements-dev.in"
        self.requirements_dev_txt = self.project_root / "requirements-dev.txt"
        self.pyproject_toml = self.project_root / "pyproject.toml"
        self.poetry_lock = self.project_root / "poetry.lock"
        
    def detect_tool(self) -> str:
        """Detect which dependency management tool is being used."""
        if self.poetry_lock.exists() or self.pyproject_toml.exists():
            with open(self.pyproject_toml, 'r') as f:
                content = f.read()
                if '[tool.poetry]' in content:
                    return 'poetry'
        
        if self.requirements_in.exists() or self.requirements_txt.exists():
            return 'pip-tools'
        
        return 'unknown'
    
    def check_dependencies(self):
        """Check if required tools are installed."""
        tool = self.detect_tool()
        
        if tool == 'pip-tools':
            try:
                subprocess.run(['pip-compile', '--version'], 
                             capture_output=True, check=True)
                print("✓ pip-tools is installed")
                return True
            except (subprocess.CalledProcessError, FileNotFoundError):
                print("✗ pip-tools not found. Install with: pip install pip-tools")
                return False
        
        elif tool == 'poetry':
            try:
                subprocess.run(['poetry', '--version'], 
                             capture_output=True, check=True)
                print("✓ Poetry is installed")
                return True
            except (subprocess.CalledProcessError, FileNotFoundError):
                print("✗ Poetry not found. Install from: https://python-poetry.org/docs/#installation")
                return False
        
        return False
    
    def init_pip_tools(self):
        """Initialize pip-tools project structure."""
        print("Initializing pip-tools structure...")
        
        if not self.requirements_in.exists():
            with open(self.requirements_in, 'w') as f:
                f.write("# Core dependencies\n")
                f.write("# Add your packages here, e.g.:\n")
                f.write("# requests>=2.28.0\n")
                f.write("# flask~=2.3.0\n")
            print(f"✓ Created {self.requirements_in}")
        
        if not self.requirements_dev_in.exists():
            with open(self.requirements_dev_in, 'w') as f:
                f.write("# Development dependencies\n")
                f.write("-c requirements.txt\n")
                f.write("# pytest>=7.0.0\n")
                f.write("# black>=23.0.0\n")
                f.write("# mypy>=1.0.0\n")
            print(f"✓ Created {self.requirements_dev_in}")
        
        print("\nNext steps:")
        print(f"1. Add your dependencies to {self.requirements_in}")
        print(f"2. Add development dependencies to {self.requirements_dev_in}")
        print("3. Run: python dependency_lock_manager.py compile")
    
    def init_poetry(self):
        """Initialize Poetry project."""
        print("Initializing Poetry project...")
        
        if not self.pyproject_toml.exists():
            result = subprocess.run(['poetry', 'init', '--no-interaction'],
                                  cwd=self.project_root,
                                  capture_output=True)
            if result.returncode == 0:
                print("✓ Created pyproject.toml")
            else:
                print("✗ Failed to initialize Poetry project")
                print(result.stderr.decode())
                return
        
        print("\nNext steps:")
        print("1. Add dependencies with: poetry add <package>")
        print("2. Add dev dependencies with: poetry add --group dev <package>")
        print("3. Lock dependencies with: python dependency_lock_manager.py lock")
    
    def compile_pip_requirements(self, upgrade: bool = False, 
                                upgrade_package: Optional[str] = None,
                                generate_hashes: bool = True):
        """Compile requirements files using pip-compile."""
        print("Compiling requirements with pip-compile...")
        
        base_cmd = ['pip-compile', '--resolver=backtracking', '--verbose']
        
        if generate_hashes:
            base_cmd.append('--generate-hashes')
        
        if upgrade:
            base_cmd.append('--upgrade')
        elif upgrade_package:
            base_cmd.extend(['--upgrade-package', upgrade_package])
        
        # Compile main requirements
        if self.requirements_in.exists():
            cmd = base_cmd + [
                '--output-file', str(self.requirements_txt),
                str(self.requirements_in)
            ]
            print(f"\n→ Compiling {self.requirements_in}...")
            result = subprocess.run(cmd, cwd=self.project_root)
            
            if result.returncode != 0:
                print("✗ Failed to compile requirements.txt")
                return False
            print(f"✓ Generated {self.requirements_txt}")
        
        # Compile dev requirements
        if self.requirements_dev_in.exists():
            cmd = base_cmd + [
                '--output-file', str(self.requirements_dev_txt),
                str(self.requirements_dev_in)
            ]
            print(f"\n→ Compiling {self.requirements_dev_in}...")
            result = subprocess.run(cmd, cwd=self.project_root)
            
            if result.returncode != 0:
                print("✗ Failed to compile requirements-dev.txt")
                return False
            print(f"✓ Generated {self.requirements_dev_txt}")
        
        print("\n✓ Compilation complete!")
        return True
    
    def sync_pip_environment(self, dev: bool = False):
        """Sync environment with locked requirements."""
        print("Syncing environment with pip-sync...")
        
        try:
            subprocess.run(['pip-sync', '--version'], 
                         capture_output=True, check=True)
        except (subprocess.CalledProcessError, FileNotFoundError):
            print("✗ pip-sync not found (part of pip-tools)")
            return False
        
        files = [str(self.requirements_txt)]
        if dev and self.requirements_dev_txt.exists():
            files.append(str(self.requirements_dev_txt))
        
        cmd = ['pip-sync'] + files
        print(f"\n→ Running: {' '.join(cmd)}")
        result = subprocess.run(cmd, cwd=self.project_root)
        
        if result.returncode == 0:
            print("✓ Environment synced successfully")
            return True
        else:
            print("✗ Failed to sync environment")
            return False
    
    def poetry_lock(self, update: bool = False, package: Optional[str] = None):
        """Lock dependencies with Poetry."""
        print("Locking dependencies with Poetry...")
        
        if update and package:
            cmd = ['poetry', 'update', package]
            print(f"\n→ Updating {package}...")
        elif update:
            cmd = ['poetry', 'update']
            print("\n→ Updating all dependencies...")
        else:
            cmd = ['poetry', 'lock', '--no-update']
            print("\n→ Locking dependencies...")
        
        result = subprocess.run(cmd, cwd=self.project_root)
        
        if result.returncode == 0:
            print("✓ Dependencies locked successfully")
            return True
        else:
            print("✗ Failed to lock dependencies")
            return False
    
    def poetry_install(self, no_dev: bool = False):
        """Install dependencies using Poetry."""
        print("Installing dependencies with Poetry...")
        
        cmd = ['poetry', 'install']
        if no_dev:
            cmd.append('--no-dev')
        
        result = subprocess.run(cmd, cwd=self.project_root)
        
        if result.returncode == 0:
            print("✓ Dependencies installed successfully")
            return True
        else:
            print("✗ Failed to install dependencies")
            return False
    
    def verify_hashes(self, requirements_file: Optional[Path] = None):
        """Verify that requirements file has hashes."""
        if requirements_file is None:
            requirements_file = self.requirements_txt
        
        if not requirements_file.exists():
            print(f"✗ {requirements_file} not found")
            return False
        
        with open(requirements_file, 'r') as f:
            content = f.read()
        
        # Count packages and hashes
        package_lines = [l for l in content.split('\n') 
                        if l.strip() and not l.strip().startswith('#') 
                        and not l.strip().startswith('-')]
        hash_lines = [l for l in package_lines if '--hash=' in l]
        
        print(f"\n{requirements_file}:")
        print(f"  Packages: {len(package_lines)}")
        print(f"  With hashes: {len(hash_lines)}")
        
        if len(hash_lines) == len(package_lines):
            print("  ✓ All packages have hashes")
            return True
        else:
            print(f"  ✗ {len(package_lines) - len(hash_lines)} packages missing hashes")
            return False
    
    def show_outdated(self):
        """Show outdated dependencies."""
        tool = self.detect_tool()
        
        if tool == 'poetry':
            print("Checking for outdated Poetry dependencies...")
            subprocess.run(['poetry', 'show', '--outdated'], 
                         cwd=self.project_root)
        
        elif tool == 'pip-tools':
            print("Checking for outdated pip dependencies...")
            print("(Running pip list --outdated)")
            subprocess.run(['pip', 'list', '--outdated'])
    
    def export_for_docker(self, output_file: str = "requirements-docker.txt"):
        """Export requirements for Docker without hashes for faster builds."""
        tool = self.detect_tool()
        output_path = self.project_root / output_file
        
        if tool == 'poetry':
            print("Exporting Poetry dependencies for Docker...")
            cmd = ['poetry', 'export', '-f', 'requirements.txt', 
                   '--without-hashes', '-o', str(output_path)]
            result = subprocess.run(cmd, cwd=self.project_root)
            
            if result.returncode == 0:
                print(f"✓ Exported to {output_path}")
                return True
        
        elif tool == 'pip-tools':
            print("Creating requirements without hashes for Docker...")
            if not self.requirements_txt.exists():
                print("✗ requirements.txt not found")
                return False
            
            with open(self.requirements_txt, 'r') as f:
                lines = f.readlines()
            
            with open(output_path, 'w') as f:
                for line in lines:
                    if '--hash=' in line:
                        # Remove hash part
                        line = re.sub(r'\s+--hash=\S+', '', line)
                        line = line.strip() + '\n'
                    f.write(line)
            
            print(f"✓ Exported to {output_path}")
            return True
        
        return False
    
    def generate_report(self, output_file: str = "dependency_report.txt"):
        """Generate a dependency report."""
        tool = self.detect_tool()
        output_path = self.project_root / output_file
        
        with open(output_path, 'w') as f:
            f.write("=" * 70 + "\n")
            f.write("DEPENDENCY REPORT\n")
            f.write(f"Generated: {datetime.now().isoformat()}\n")
            f.write(f"Tool: {tool}\n")
            f.write("=" * 70 + "\n\n")
            
            if tool == 'poetry':
                result = subprocess.run(['poetry', 'show', '--tree'],
                                      capture_output=True, text=True,
                                      cwd=self.project_root)
                f.write("Dependency Tree:\n")
                f.write(result.stdout)
                
                result = subprocess.run(['poetry', 'show'],
                                      capture_output=True, text=True,
                                      cwd=self.project_root)
                f.write("\n\nAll Dependencies:\n")
                f.write(result.stdout)
            
            elif tool == 'pip-tools':
                if self.requirements_txt.exists():
                    with open(self.requirements_txt, 'r') as req:
                        f.write("Production Dependencies:\n")
                        f.write(req.read())
                        f.write("\n\n")
                
                if self.requirements_dev_txt.exists():
                    with open(self.requirements_dev_txt, 'r') as req:
                        f.write("Development Dependencies:\n")
                        f.write(req.read())
        
        print(f"✓ Report generated: {output_path}")
        return True


