def main():
    parser = argparse.ArgumentParser(
        description='Manage Python dependency lock files',
        formatter_class=argparse.RawDescriptionHelpFormatter
    )
    
    subparsers = parser.add_subparsers(dest='command', help='Commands')
    
    # Init command
    init_parser = subparsers.add_parser('init', help='Initialize dependency management')
    init_parser.add_argument('--tool', choices=['pip-tools', 'poetry'], 
                            help='Tool to initialize')
    
    # Compile command (pip-tools)
    compile_parser = subparsers.add_parser('compile', 
                                          help='Compile requirements files (pip-tools)')
    compile_parser.add_argument('--upgrade', action='store_true',
                               help='Upgrade all dependencies')
    compile_parser.add_argument('--upgrade-package', 
                               help='Upgrade specific package')
    compile_parser.add_argument('--no-hashes', action='store_true',
                               help='Do not generate hashes')
    
    # Sync command (pip-tools)
    sync_parser = subparsers.add_parser('sync', 
                                       help='Sync environment (pip-tools)')
    sync_parser.add_argument('--dev', action='store_true',
                            help='Include development dependencies')
    
    # Lock command (Poetry)
    lock_parser = subparsers.add_parser('lock', 
                                       help='Lock dependencies (Poetry)')
    lock_parser.add_argument('--update', action='store_true',
                            help='Update dependencies')
    lock_parser.add_argument('--package', 
                            help='Update specific package')
    
    # Install command (Poetry)
    install_parser = subparsers.add_parser('install', 
                                          help='Install dependencies (Poetry)')
    install_parser.add_argument('--no-dev', action='store_true',
                               help='Skip development dependencies')
    
    # Other commands
    subparsers.add_parser('check', help='Check installed tools')
    subparsers.add_parser('verify', help='Verify hashes in requirements')
    subparsers.add_parser('outdated', help='Show outdated dependencies')
    subparsers.add_parser('export-docker', help='Export for Docker')
    subparsers.add_parser('report', help='Generate dependency report')
    subparsers.add_parser('guide', help='Show usage guide')
    
    args = parser.parse_args()
    
    if not args.command or args.command == 'guide':
        print_usage_guide()
        return
    
    manager = DependencyLockManager()
    
    if args.command == 'check':
        manager.check_dependencies()
    
    elif args.command == 'init':
        if args.tool == 'poetry':
            manager.init_poetry()
        elif args.tool == 'pip-tools':
            manager.init_pip_tools()
        else:
            # Auto-detect or prompt
            print("No tool specified. Defaulting to pip-tools.")
            manager.init_pip_tools()
    
    elif args.command == 'compile':
        if not manager.check_dependencies():
            sys.exit(1)
        manager.compile_pip_requirements(
            upgrade=args.upgrade,
            upgrade_package=args.upgrade_package,
            generate_hashes=not args.no_hashes
        )
    
    elif args.command == 'sync':
        if not manager.check_dependencies():
            sys.exit(1)
        manager.sync_pip_environment(dev=args.dev)
    
    elif args.command == 'lock':
        if not manager.check_dependencies():
            sys.exit(1)
        manager.poetry_lock(update=args.update, package=args.package)
    
    elif args.command == 'install':
        if not manager.check_dependencies():
            sys.exit(1)
        manager.poetry_install(no_dev=args.no_dev)
    
    elif args.command == 'verify':
        manager.verify_hashes()
        if manager.requirements_dev_txt.exists():
            manager.verify_hashes(manager.requirements_dev_txt)
    
    elif args.command == 'outdated':
        manager.show_outdated()
    
    elif args.command == 'export-docker':
        manager.export_for_docker()
    
    elif args.command == 'report':
        manager.generate_report()


if __name__ == '__main__':
    main()